// Behavioral contract test: the *built* parser must classify every canonical
// Event-B spelling exactly as `rossi gen-grammars` says it should.
//
// `tokens.json` is generated by `rossi gen-grammars` from the canonical token
// tables and byte-checked on the rossi side, so it is the source of truth for
// "which spelling is which kind of token". Here we parse each spelling with the
// compiled grammar and assert it tokenizes to the matching node. Because this
// asserts the parser's *observable behavior* (not the grammar's source text), it
// keeps verifying that the generated core matches gen-grammars even after the
// grammar is hand-extended with structural rules.

import assert from "node:assert/strict";
import { test } from "node:test";
import { readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import Parser from "tree-sitter";
import EventB from "../bindings/node/index.js";

const manifest = JSON.parse(
  readFileSync(fileURLToPath(new URL("./tokens.json", import.meta.url)), "utf8"),
);

const parser = new Parser();
parser.setLanguage(EventB);

for (const [node, spellings] of Object.entries(manifest)) {
  test(`every ${node} spelling tokenizes as ${node}`, () => {
    for (const spelling of spellings) {
      const root = parser.parse(spelling).rootNode;
      assert.equal(
        root.hasError,
        false,
        `parsing ${JSON.stringify(spelling)} produced a parse error: ${root.toString()}`,
      );
      assert.equal(
        root.namedChildCount,
        1,
        `expected ${JSON.stringify(spelling)} to be a single token, got: ${root.toString()}`,
      );
      assert.equal(
        root.namedChild(0).type,
        node,
        `expected ${JSON.stringify(spelling)} to be a ${node}, got ${root.namedChild(0).type}`,
      );
    }
  });
}

test("manifest is non-empty and covers the coloured classes", () => {
  const nodes = Object.keys(manifest);
  for (const required of [
    "keyword",
    "status_keyword",
    "constant_sym",
    "constant_word",
    "builtin",
    "operator_sym",
    "operator_word",
  ]) {
    assert.ok(nodes.includes(required), `manifest is missing node class ${required}`);
    assert.ok(manifest[required].length > 0, `manifest class ${required} is empty`);
  }
});
